def test_error_responses_include_security_and_request_headers(tmp_path: Path):
    client = create_test_client(tmp_path)
    response = client.get("/api/v1/experiments/missing-exp", headers={"host": "testserver"})

    assert response.status_code == 404
    assert response.headers.get("X-Request-ID")
    assert response.headers.get("X-Content-Type-Options") == "nosniff"
    assert response.headers.get("X-Frame-Options") == "DENY"


def test_phase1_auth_required_contract(tmp_path: Path, monkeypatch):
    """Require API key on protected routes and return normalized unauthorized responses."""
    client = create_test_client(tmp_path)
    monkeypatch.setattr(main_module, "settings", replace(main_module.settings, api_key="phase1-secret"))

    unauthorized = client.get("/api/v1/prompts", headers={"host": "testserver"})
    _assert_error_contract(
        unauthorized,
        expected_status=401,
        expected_code="unauthorized",
        expected_message="api_key_invalid",
    )

    invalid_key = client.get("/api/v1/prompts", headers={"host": "testserver", "X-API-Key": "wrong"})
    _assert_error_contract(
        invalid_key,
        expected_status=401,
        expected_code="unauthorized",
        expected_message="api_key_invalid",
    )

    authorized = client.get("/api/v1/prompts", headers={"host": "testserver", "X-API-Key": "phase1-secret"})
    assert authorized.status_code == 200


