def test_rate_limit_enforcement_contract(tmp_path: Path):
    client = create_test_client(tmp_path, rate_limit_per_minute=1)

    first = client.get("/api/v1/prompts", headers={"host": "testserver"})
    assert first.status_code == 200

    second = client.get("/api/v1/prompts", headers={"host": "testserver"})
    _assert_error_contract(
        second,
        expected_status=429,
        expected_code="rate_limited",
        expected_message="rate_limited",
    )
    assert second.headers.get("Retry-After") == "60"
    assert second.headers.get("X-Request-ID")
